HAT_LINES: dict[Hat, str] = {"none": "", "crown": "   \\^^^/    ", "tophat": "   [___]    ", "propeller": "    -+-     ", "halo": "   (   )    ", "wizard": "    /^\\     ", "beanie": "   (___)    ", "tinyduck": "    ,>      "}


def render_sprite(bones: CompanionLike, frame: int = 0) -> list[str]:
    frames = BODIES[bones.species]
    lines = [line.replace("{E}", bones.eye) for line in frames[frame % len(frames)]]
    if bones.hat != "none" and not lines[0].strip():
        lines[0] = HAT_LINES[bones.hat]
    if not lines[0].strip() and all(not item[0].strip() for item in frames):
        lines = lines[1:]
    return lines


def sprite_frame_count(species: Species) -> int:
    return len(BODIES[species])


def render_face(bones: CompanionLike) -> str:
    eye = bones.eye
    return {
        "duck": f"({eye}>", "goose": f"({eye}>", "blob": f"({eye}{eye})", "cat": f"={eye}ω{eye}=",
        "dragon": f"<{eye}~{eye}>", "octopus": f"~({eye}{eye})~", "owl": f"({eye})({eye})", "penguin": f"({eye}>)",
        "turtle": f"[{eye}_{eye}]", "snail": f"{eye}(@)", "ghost": f"/{eye}{eye}\\", "axolotl": f"}}{eye}.{eye}{{",
        "capybara": f"({eye}oo{eye})", "cactus": f"|{eye}  {eye}|", "robot": f"[{eye}{eye}]", "rabbit": f"({eye}..{eye})",
        "mushroom": f"|{eye}  {eye}|", "chonk": f"({eye}.{eye})",
    }[bones.species]
